-- Cleanup for local QA data used by the venue check-in pipeline verification.
-- This script only targets deterministic QA IDs and the qa-test-checkins-org slug.

BEGIN;

DELETE FROM public.user_events
WHERE user_id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
)
OR meta->>'visit_id' IN (
  '11111111-1111-4111-8111-111111111401',
  '11111111-1111-4111-8111-111111111402',
  '11111111-1111-4111-8111-111111111403',
  '11111111-1111-4111-8111-111111111404',
  '11111111-1111-4111-8111-111111111405',
  '11111111-1111-4111-8111-111111111406',
  '11111111-1111-4111-8111-111111111407'
);

DELETE FROM public.venue_visits
WHERE id IN (
  '11111111-1111-4111-8111-111111111401',
  '11111111-1111-4111-8111-111111111402',
  '11111111-1111-4111-8111-111111111403',
  '11111111-1111-4111-8111-111111111404',
  '11111111-1111-4111-8111-111111111405',
  '11111111-1111-4111-8111-111111111406',
  '11111111-1111-4111-8111-111111111407'
);

DELETE FROM public.user_follows
WHERE follower_id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
)
OR following_user_id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
);

DELETE FROM public.user_preferences
WHERE user_id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
);

DELETE FROM public.user_profiles
WHERE user_id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
);

DELETE FROM auth.users
WHERE id IN (
  '11111111-1111-4111-8111-111111111201',
  '11111111-1111-4111-8111-111111111202',
  '11111111-1111-4111-8111-111111111203'
);

DELETE FROM public.venues
WHERE id IN (
  '11111111-1111-4111-8111-111111111301',
  '11111111-1111-4111-8111-111111111302',
  '11111111-1111-4111-8111-111111111303',
  '11111111-1111-4111-8111-111111111304',
  '11111111-1111-4111-8111-111111111305'
);

DELETE FROM public.organizations
WHERE id = '11111111-1111-4111-8111-111111111101'
   OR slug = 'qa-test-checkins-org';

COMMIT;
